/** Supported orchestration profiles in stable CLI/schema order. */
export const ORCHESTRATION_PROFILE_NAMES = [
  "single-session",
  "balanced",
  "orchestrated",
] as const;

/** One supported preset-controlled orchestration profile. */
export type OrchestrationProfile = (typeof ORCHESTRATION_PROFILE_NAMES)[number];

/** Optional canonical vvoc configuration section. */
export type OrchestrationConfig = {
  profile: OrchestrationProfile;
};

/** Capabilities consumed by prompt-producing plugins without model inference. */
export type ResolvedOrchestrationPolicy = {
  profile: OrchestrationProfile;
  controllerSystemContext: string;
  workflowGuidance: "review-only" | "selective" | "tracked";
};

/** Backward-compatible profile used when an old valid v3 document omits orchestration. */
export const DEFAULT_ORCHESTRATION_PROFILE: OrchestrationProfile = "balanced";

/** Builds a normalized section, defaulting only when the section is absent. */
export function createOrchestrationConfig(
  value?: Partial<OrchestrationConfig>,
): OrchestrationConfig;

/** Validates a CLI or config profile string and throws with allowed choices on failure. */
export function parseOrchestrationProfile(value: unknown, operation: string): OrchestrationProfile;

/** Resolves one immutable concrete policy from structurally compatible config input. */
export function resolveOrchestrationPolicy(config: {
  orchestration?: Partial<OrchestrationConfig>;
}): ResolvedOrchestrationPolicy;

/** A named preset may optionally change the active orchestration profile. */
export type VvocPreset = {
  description?: string;
  agents: VvocPresetAgents;
  orchestration?: OrchestrationConfig;
};

/** Canonical normalized config; raw valid v3 input may omit orchestration. */
export type VvocConfig = {
  $schema: string;
  version: number;
  roles: Record<string, string>;
  orchestration?: OrchestrationConfig;
  guardian: GuardianConfig;
  secretsRedaction: SecretsRedactionConfig;
  presets: VvocPresets;
  plugins: VvocPluginToggleConfig;
};

/** Fresh canonical config writes an explicit balanced profile. */
export function createDefaultVvocConfig(): VvocConfig;

/** Render preserves a valid explicit profile and normalizes an omitted profile to balanced. */
export function renderVvocConfig(config?: VvocConfig): string;

/** Result of applying the optional orchestration part of a preset. */
export type AppliedPresetOrchestrationChange = {
  profile: OrchestrationProfile;
  action: "updated" | "kept" | "unchanged";
};

/** Applies all declared preset fields atomically to one scoped vvoc.json document. */
export async function applyPreset(
  presetName: string,
  options?: { cwd?: string; configDir?: string; scope?: ConfigWriteScope },
): Promise<{
  name: string;
  preset: VvocPreset;
  changes: AppliedPresetChange[];
  orchestration: AppliedPresetOrchestrationChange;
  path: string;
}>;

// Built-in mapping contract:
// vv-openai, vv-osovv, vv-osovv-cheap -> single-session
// vv-zai, vv-minimax, vv-deepseek -> balanced

const VV_CONTROLLER_AGENT = "vv-controller" as const;

/** Returns universal primary guidance and, only for vv-controller, one concrete policy. */
function getSystemContextsForAgent(
  agentName: string | undefined,
  policy: ResolvedOrchestrationPolicy,
): readonly string[];

export const SystemContextInjectionPlugin: Plugin = async ({ directory }) => {
  const vvoc = await loadVvocConfig({ cwd: directory });
  const policy = resolveOrchestrationPolicy(vvoc.config);
  // Existing skill-path registration and known-subagent filtering remain intact.
  return {} as Awaited<ReturnType<Plugin>>;
};

/** Returns the exact workflow instruction compatible with one resolved policy. */
function getWorkflowSystemInstruction(
  policy: ResolvedOrchestrationPolicy,
): string {
  switch (policy.workflowGuidance) {
    case "review-only":
      return REVIEW_ONLY_WORKFLOW_SYSTEM_INSTRUCTION;
    case "selective":
      return SELECTIVE_WORKFLOW_SYSTEM_INSTRUCTION;
    case "tracked":
      return workflowSystemInstructionTemplate.trim();
  }
}

// templates/skills/vv-execute/SKILL.md frontmatter contract:
// description: Use when given an approved plan.xml to validate it, choose an execution mode with the user, and execute tasks with verification and commits

describe("managed workflow skill prompts", () => {
  test("vv-execute hides mode names in discovery metadata but retains explicit choice after load", async () => {});
  test("vv-review remains reviewer-based, findings-only, and never delegates to implementers", async () => {});
});

/** Result returned by a scoped orchestration profile write. */
export type OrchestrationWriteResult = {
  action: "updated" | "kept";
  profile: OrchestrationProfile;
  path: string;
};

/** Reads one resolved profile and selected source without mutation. */
export async function showOrchestrationProfile(options?: {
  cwd?: string;
  configDir?: string;
  scope?: ConfigReadScope;
}): Promise<{ profile: OrchestrationProfile; source: ConfigSource }>;

/** Writes one explicit profile to global or project vvoc.json. */
export async function setOrchestrationProfile(
  profile: OrchestrationProfile,
  options?: { cwd?: string; configDir?: string; scope?: ConfigWriteScope },
): Promise<OrchestrationWriteResult>;

import orchestration from "./commands/orchestration.js";

const main = defineCommand({
  subCommands: {
    orchestration,
  },
});

const VVOC_ORCHESTRATION_COMMANDS = ["show", "set"] as const;
const VVOC_ORCHESTRATION_PROFILES = [...ORCHESTRATION_PROFILE_NAMES];

export type InstallationInspection = {
  orchestration: {
    profile?: OrchestrationProfile;
  };
  // Existing opencode, vvoc, guardian, secretsRedaction, roles, warnings, problems remain.
};

// status output contract:
// Orchestration profile: single-session
// vvoc source: project /path/to/.vvoc/vvoc.json
